NoJS.use({
  name: 'auth',
  install(app, options) {
    app.interceptor('request', (url, opts) => {
      opts.headers['Authorization'] = 'Bearer ' + token;
      return opts;
    });
  }
});

const myPlugin = {
  name: 'analytics',
  version: '1.0.0',
  capabilities: ['interceptors', 'globals'],
  install(app, options) { /* sync setup */ },
  init(app) { /* DOM ready, async OK */ },
  dispose(app) { /* cleanup, async OK */ }
};

function myLogger(app, options) {
  app.interceptor('request', (url, opts) => {
    console.log(`[${options.prefix}]`, url);
    return opts;
  });
}

NoJS.use(myLogger, { prefix: 'API' });

// Plugin A registers $theme
// Plugin B tries to overwrite $theme
// Warning: Global "$theme" owned by "pluginA" is being overwritten.

app.interceptor('request', (url, opts) => {
  if (!navigator.onLine) {
    return { [app.CANCEL]: true };
  }
  return opts;
});

app.interceptor('request', (url, opts) => {
  if (cache.has(url)) {
    return { [app.RESPOND]: cache.get(url) };
  }
  return opts;
});

app.interceptor('response', (response, url) => {
  if (url.includes('/users')) {
    return { [app.REPLACE]: { normalized: true } };
  }
  return response;
});
